def load():
    s = open("quotes.js", encoding="utf-8").read()
    i, j = s.index("["), s.rindex("]")
    return json.loads(s[i:j+1])

def save(arr):
    open("quotes.js", "w", encoding="utf-8").write(
        "window.QUOTES = " + json.dumps(arr, ensure_ascii=False, indent=1) + ";\n")

def main():
    text = (os.environ.get("QUOTE_TEXT") or "").strip()
    author = (os.environ.get("QUOTE_AUTHOR") or "").strip()
    icon_name = (os.environ.get("QUOTE_ICON") or "quote").strip().lower()
    if not text:
        sys.exit("No quote text provided.")
    arr = load()
    q = html.escape("\u201c" + text + "\u201d").replace("\n\n", "<br><br>").replace("\n", "<br>")
    arr.append({"q": q, "a": html.escape(author), "i": ICONS.get(icon_name, ICONS["quote"])})
    save(arr)
    print(f"Added quote by {author or 'Unknown'}; total now {len(arr)}.")

if __name__ == "__main__":
    main()
